                    animation-delay: calc( 0.035s * var(--oGNo) );
                    opacity: var(--optgroupOpacity)!important;

                    option {
                        animation: rotateInOption;
                        animation-duration: 0.6s;
                        animation-fill-mode: forwards;
                        animation-delay: calc( 0.045s * var(--oGNo) );
                    }

