        height: 100vh;
        transform-origin: 50% 50%;
        overflow: clip;
        z-index: -1;

        .bgDiv {
            position: absolute;
            width: 600px;
            height: 600px;
            border-radius: 50%;
            mix-blend-mode: color;

            &#bd1 {
                margin-left: -80px;
                margin-top: -80px;
                z-index: 1;
                opacity: 0.75;
                background-image: linear-gradient( 315deg, var(--bd1) 30%, transparent 100% );
            }
            &#bd2 {
                margin-right: -80px;
                margin-top: -80px;
                z-index: 2;
                opacity: 0.75;
                background-image: linear-gradient( 225deg, var(--bd2) 30%, transparent 100% );
            }
            &#bd3 {
                margin-top: 80px;
                z-index: 3;
                opacity: 0.75;
                background-image: linear-gradient( 45deg, var(--bd3) 30%, transparent 100% );
            }

        }

        #treyMix {
            position: absolute;
            z-index: 6;
            width: 600px;
            height: 600px;
            transform-origin: 50% 50%;
            background-image: linear-gradient(var(--bd1), var(--bd2), var(--bd3));
            animation: rotateBg 10s cubic-bezier(0.67, 0.33, 0.33, 0.67) alternate infinite;
            border-radius: 33% 67% 67% 33%/33% 33% 67% 67%;

        }

        #treyBlend {
            position: absolute;
            width: 700px;
            height: 700px;
            z-index: 7;
            background: var(--bd4);
            background: radial-gradient(circle,var(--bd4) 70%, transparent 100%);
            border-radius: 50%;
            opacity: 0.5;
        }

    }

}


#bgBlur {
    position: absolute;
    left: 0px;
    top: 0px;
    z-index: 8;
    width: 100vw;
    height: 100vh;
    backdrop-filter: blur(80px)
}

@keyframes rotateBg { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
